class Solution:
    def isCircularSentence(self, sentence):
        words = sentence.split(' ')
        n = len(words)
        for idx in range(n):
            current = words[idx]
            nxt = words[(idx + 1) % n]
            if current[-1] != nxt[0]:
                return False
        return True

