var isCircularSentence = function(sentence) {
    const words = sentence.split(' ');
    for (let i = 0; i < words.length; i++) {
        const nxt = words[(i + 1) % words.length];
        if (words[i][words[i].length - 1] !== nxt[0]) {
            return false;
        }
    }
    return true;
};
